import React, { useEffect, useState } from "react";
import api from "../services/api";

function BodyMetricsPage() {
  const [form, setForm] = useState({
    gender: "female",
    age: "",
    height_cm: "",
    current_weight_kg: "",
    activity_level_id: "2",
    goal_calories: ""
  });

  const [result, setResult] = useState(null);

  const loadMetrics = async () => {
    try {
      const res = await api.get("/body-metrics");
      setResult(res.data);
    } catch (err) {
      setResult(null);
    }
  };

  useEffect(() => {
    loadMetrics();
  }, []);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const res = await api.post("/body-metrics", form);
      alert(res.data.message);
      loadMetrics();
    } catch (err) {
      alert(err.response?.data?.error || "Lỗi lưu thông số cơ thể");
    }
  };

  return (
    <div>
      <h2>Thông số cơ thể</h2>

      <form onSubmit={handleSubmit}>
        <label>Giới tính:</label>
        <br />
        <select name="gender" value={form.gender} onChange={handleChange}>
          <option value="male">Nam</option>
          <option value="female">Nữ</option>
        </select>
        <br /><br />

        <label>Tuổi:</label>
        <br />
        <input
          name="age"
          type="number"
          placeholder="Tuổi"
          value={form.age}
          onChange={handleChange}
        />
        <br /><br />

        <label>Chiều cao (cm):</label>
        <br />
        <input
          name="height_cm"
          type="number"
          step="0.1"
          placeholder="Chiều cao"
          value={form.height_cm}
          onChange={handleChange}
        />
        <br /><br />

        <label>Cân nặng (kg):</label>
        <br />
        <input
          name="current_weight_kg"
          type="number"
          step="0.1"
          placeholder="Cân nặng"
          value={form.current_weight_kg}
          onChange={handleChange}
        />
        <br /><br />

        <label>Mức độ vận động (1-4):</label>
        <br />
        <input
          name="activity_level_id"
          type="number"
          placeholder="1-4"
          value={form.activity_level_id}
          onChange={handleChange}
        />
        <br /><br />

        <label>Mục tiêu calo:</label>
        <br />
        <input
          name="goal_calories"
          type="number"
          step="0.1"
          placeholder="Mục tiêu calo"
          value={form.goal_calories}
          onChange={handleChange}
        />
        <br /><br />

        <button type="submit">Lưu thông số</button>
      </form>

      {result && (
        <div style={{ marginTop: "20px" }}>
          <h3>Kết quả chỉ số cơ thể</h3>
          <p><strong>BMI:</strong> {result.BMI}</p>
          <p><strong>BMR:</strong> {result.BMR}</p>
          <p><strong>TDEE:</strong> {result.TDEE}</p>
        </div>
      )}
    </div>
  );
}

export default BodyMetricsPage;
